// ── Reimagine variants — real Stardust prototypes of inside.adobe.com ─────────
// Three directions Stardust generated from one URL (inside.adobe.com), served as
// REAL hosted HTML pages (src/prototype/inside-{a,b,c}.html) so "Open prototype"
// opens a living, scrollable page — variant C even animates (live ticker, count-
// ups, scroll reveals). The thumbnail is an inlined base64 JPEG (validation
// screenshot) for the result strip. `href` is resolved at runtime from the app
// origin (see hostedHref) so it works on :5173 and under the da-playground build.
// Demo-only; tree-shakes out of a normal client:build.
// Source: ~/Desktop/stardust-outputs/stardust/prototypes/home-{A,B,C}.
export interface ReimagineVariant {
  id: string;
  label: string;
  note: string;
  file: string;   // page under /prototype, resolved to an absolute URL at runtime
  thumb: string;  // inlined base64 JPEG for the result strip
}
const TA = 'data:image/jpeg;base64,';
const TB = 'data:image/jpeg;base64,';
const TC = 'data:image/jpeg;base64,';

export const REIMAGINE_VARIANTS: ReimagineVariant[] = [
  { id: 'faithful', label: 'Faithful +', note: 'On-brand, refined. Closest to today.', file: 'inside-a.html', thumb: TA },
  { id: 'editorial', label: 'Editorial', note: 'Display type, numbered story index.', file: 'inside-b.html', thumb: TB },
  { id: 'cinematic', label: 'Cinematic', note: 'Live ticker, motion, count-ups.', file: 'inside-c.html', thumb: TC },
];
